func evidence_httpproto_write_ambiguity_retry_1o30tm(accepted bool, readComplete bool, deadlineExpired bool, peerClosed bool) (string, bool) {
	state, reusable := "accept", false
	if accepted { state = "reading" }
	if accepted && readComplete { state, reusable = "message-complete", true }
	if deadlineExpired { state, reusable = "timeout", false }
	if peerClosed && !readComplete { state, reusable = "incomplete-eof", false }
	return state, reusable
}
